parameters.jsCode:
// Parse panel management request
const body = $input.first().json.body || $input.first().json;

const validActions = ['create_room', 'join_room', 'leave_room', 'kick_guest', 'mute_guest', 'unmute_guest', 'enable_video', 'disable_video', 'promote_to_host', 'get_room_state'];
const action = body.action;

if (!validActions.includes(action)) {
  throw new Error('Invalid panel action: ' + action);
}

return [{
  json: {
    action: action,
    roomId: body.roomId || crypto.randomUUID(),
    userId: body.userId,
    streamId: body.streamId,
    targetUserId: body.targetUserId,
    displayName: body.displayName,
    maxGuests: Math.min(body.maxGuests || 20, 20),
    rtcConfig: body.rtcConfig || {
      iceServers: [
        { urls: 'stun:stun.l.google.com:19302' },
        { urls: 'stun:stun1.l.google.com:19302' }
      ]
    },
    timestamp: new Date().toISOString(),
    requestId: crypto.randomUUID()
  }
}];

// Create new WebRTC room
const request = $input.first().json;

const room = {
  id: request.roomId,
  streamId: request.streamId,
  hostId: request.userId,
  createdAt: new Date().toISOString(),
  maxGuests: request.maxGuests,
  guests: [],
  state: 'active',
  rtcConfig: request.rtcConfig,
  settings: {
    videoEnabled: true,
    audioEnabled: true,
    screenShareEnabled: true,
    chatEnabled: true,
    recordingEnabled: false
  }
};

return [{
  json: {
    ...request,
    room: room,
    isNewRoom: true
  }
}];

// Handle room operations
const request = $input.first().json;
let existingRoom = $input.first().json.existingRoom;

try {
  existingRoom = typeof existingRoom === 'string' ? JSON.parse(existingRoom) : existingRoom;
} catch (e) {
  // Room doesn't exist
  return [{
    json: {
      ...request,
      error: 'Room not found',
      errorCode: 'ROOM_NOT_FOUND'
    }
  }];
}

if (!existingRoom) {
  return [{
    json: {
      ...request,
      error: 'Room not found',
      errorCode: 'ROOM_NOT_FOUND'
    }
  }];
}

let room = { ...existingRoom };
let guest = null;

switch (request.action) {
  case 'join_room':
    if (room.guests.length >= room.maxGuests) {
      return [{
        json: {
          ...request,
          room: room,
          error: 'Room is full',
          errorCode: 'ROOM_FULL'
        }
      }];
    }
    guest = {
      userId: request.userId,
      displayName: request.displayName,
      joinedAt: new Date().toISOString(),
      role: 'guest',
      videoEnabled: true,
      audioEnabled: true,
      isSpeaking: false,
      connectionQuality: 'good'
    };
    room.guests.push(guest);
    break;

  case 'leave_room':
    room.guests = room.guests.filter(g => g.userId !== request.userId);
    if (room.hostId === request.userId && room.guests.length > 0) {
      // Transfer host to first guest
      room.hostId = room.guests[0].userId;
      room.guests[0].role = 'host';
    }
    break;

  case 'kick_guest':
    if (room.hostId !== request.userId) {
      return [{
        json: {
          ...request,
          room: room,
          error: 'Only host can kick guests',
          errorCode: 'PERMISSION_DENIED'
        }
      }];
    }
    room.guests = room.guests.filter(g => g.userId !== request.targetUserId);
    break;

  case 'mute_guest':
  case 'unmute_guest':
    guest = room.guests.find(g => g.userId === request.targetUserId);
    if (guest) {
      guest.audioEnabled = request.action === 'unmute_guest';
    }
    break;

  case 'enable_video':
  case 'disable_video':
    guest = room.guests.find(g => g.userId === request.userId);
    if (guest) {
      guest.videoEnabled = request.action === 'enable_video';
    }
    break;

  case 'promote_to_host':
    if (room.hostId !== request.userId) {
      return [{
        json: {
          ...request,
          room: room,
          error: 'Only host can promote guests',
          errorCode: 'PERMISSION_DENIED'
        }
      }];
    }
    const currentHost = room.guests.find(g => g.userId === room.hostId);
    if (currentHost) currentHost.role = 'guest';

    const newHost = room.guests.find(g => g.userId === request.targetUserId);
    if (newHost) {
      newHost.role = 'host';
      room.hostId = request.targetUserId;
    }
    break;
}

return [{
  json: {
    ...request,
    room: room,
    isNewRoom: false
  }
}];

// Log panel activity
const data = $input.first().json;
const activities = data.room.guests.map(guest => ({
  roomId: data.room.id,
  userId: guest.userId,
  action: data.action,
  timestamp: new Date().toISOString()
}));

return activities;

