={{ JSON.stringify({
  type: 'room_update',
  action: $json.action,
  roomId: $json.roomId,
  userId: $json.userId,
  targetUserId: $json.targetUserId,
  room: {
    id: $json.room.id,
    hostId: $json.room.hostId,
    guestCount: $json.room.guests.length,
    maxGuests: $json.room.maxGuests,
    guests: $json.room.guests.map(g => ({
      userId: g.userId,
      displayName: g.displayName,
      role: g.role,
      videoEnabled: g.videoEnabled,
      audioEnabled: g.audioEnabled
    }))
  },
  timestamp: Date.now()
}) }}

