        userId: g.userId,
        displayName: g.displayName,
        role: g.role,
        videoEnabled: g.videoEnabled,
        audioEnabled: g.audioEnabled,
        connectionQuality: g.connectionQuality
      })),
      "rtcConfig": $json.room.rtcConfig
    }
  }
}) }}
